// ═══════════════════════════════════════════════════════
// CARE PLAN GENERATOR
// Generates 12-15 prenatal visit milestones from due date
// Based on FOGSI/ACOG standard obstetric protocols
// NO AI — this is deterministic medical protocol
// ═══════════════════════════════════════════════════════

const patient = $input.all()[0].json;
const dueDate = new Date(patient.due_date);
const patientId = patient.patient_id;
const riskLevel = patient.risk_level || 'normal';

// Calculate gestational age reference points from due date
// Due date = 40 weeks from LMP
function weeksBeforeDue(weeks) {
  const d = new Date(dueDate);
  d.setDate(d.getDate() - (40 - weeks) * 7);
  return d;
}

function formatDate(d) {
  return d.toISOString().split('T')[0];
}

// Standard prenatal visit schedule (FOGSI/ACOG guidelines)
const carePlan = [
  {
    visit_number: 1,
    gestational_week: 8,
    visit_type: 'booking_visit',
    diagnostics_needed: 'cbc, blood_group, hiv_hbsag, tsh, urine_routine, dating_ultrasound',
    notes: 'First visit — confirm pregnancy, dating scan, baseline blood work'
  },
  {
    visit_number: 2,
    gestational_week: 12,
    visit_type: 'nt_scan',
    diagnostics_needed: 'ultrasound_nt, dual_marker',
    notes: 'NT scan MUST be between 11w0d and 13w6d — time-critical window'
  },
  {
    visit_number: 3,
    gestational_week: 16,
    visit_type: 'routine',
    diagnostics_needed: 'quadruple_marker_optional',
    notes: 'Routine check, optional quad marker test'
  },
  {
    visit_number: 4,
    gestational_week: 20,
    visit_type: 'anomaly_scan',
    diagnostics_needed: 'ultrasound_anomaly, cbc, blood_sugar, thyroid',
    notes: 'Anomaly scan — detailed fetal anatomy. Window: 18-22 weeks. CRITICAL.'
  },
  {
    visit_number: 5,
    gestational_week: 24,
    visit_type: 'glucose_test',
    diagnostics_needed: 'glucose_challenge_test, cbc',
    notes: 'Gestational diabetes screening — must be 24-28 weeks'
  },
  {
    visit_number: 6,
    gestational_week: 28,
    visit_type: 'routine',
    diagnostics_needed: 'growth_scan, cbc, antibody_screen_if_rh_neg',
    notes: 'Third trimester begins. Anti-D if Rh negative.'
  },
  {
    visit_number: 7,
    gestational_week: 30,
    visit_type: 'routine',
    diagnostics_needed: 'blood_pressure_monitoring',
    notes: 'Fortnightly visits begin'
  },
  {
    visit_number: 8,
    gestational_week: 32,
    visit_type: 'growth_scan',
    diagnostics_needed: 'ultrasound_growth, cbc',
    notes: 'Growth scan — check fetal weight and amniotic fluid'
  },
  {
    visit_number: 9,
    gestational_week: 34,
    visit_type: 'routine',
    diagnostics_needed: 'blood_pressure_monitoring',
    notes: 'Check presentation, discuss birth plan'
  },
  {
    visit_number: 10,
    gestational_week: 36,
    visit_type: 'growth_scan',
    diagnostics_needed: 'ultrasound_growth, gbs_swab, cbc',
    notes: 'Weekly visits begin. GBS screening. Growth scan.'
  },
  {
    visit_number: 11,
    gestational_week: 37,
    visit_type: 'weekly_check',
    diagnostics_needed: 'nst',
    notes: 'Non-stress test. Weekly from now.'
  },
  {
    visit_number: 12,
    gestational_week: 38,
    visit_type: 'weekly_check',
    diagnostics_needed: 'nst',
    notes: 'NST + cervical check'
  },
  {
    visit_number: 13,
    gestational_week: 39,
    visit_type: 'weekly_check',
    diagnostics_needed: 'nst, ultrasound_afi',
    notes: 'NST + amniotic fluid check'
  },
  {
    visit_number: 14,
    gestational_week: 40,
    visit_type: 'due_date_check',
    diagnostics_needed: 'nst, ultrasound_afi, biophysical_profile',
    notes: 'Due date. Discuss induction if no spontaneous labour.'
  }
];

// For high-risk patients, add extra monitoring visits
if (riskLevel === 'high') {
  // Add extra growth scans at 26 and 34 weeks
  carePlan.push({
    visit_number: 15,
    gestational_week: 26,
    visit_type: 'high_risk_monitoring',
    diagnostics_needed: 'ultrasound_growth, doppler',
    notes: 'Additional high-risk monitoring — growth + doppler'
  });
}

// Sort by gestational week
carePlan.sort((a, b) => a.gestational_week - b.gestational_week);

// Generate actual dates and output
const output = carePlan.map((visit, idx) => {
  const targetDate = weeksBeforeDue(visit.gestational_week);
  return {
    json: {
      patient_id: patientId,
      patient_name: patient.name,
      primary_ob: patient.primary_ob,
      visit_number: idx + 1,
      gestational_week: visit.gestational_week,
      visit_type: visit.visit_type,
      diagnostics_needed: visit.diagnostics_needed,
      target_date: formatDate(targetDate),
      status: 'pending',
      notes: visit.notes,
      lab_time: '',
      scan_time: '',
      consultation_time: '',
      scheduled_date: ''
    }
  };
});

return output;

// ═══════════════════════════════════════════════════════
// BUNDLED VISIT SCHEDULER
// Books the FIRST upcoming visit as a coordinated bundle:
//   Lab slot → Scan slot → Consultation slot
// Sequence: diagnostics FIRST, consultation LAST
// ═══════════════════════════════════════════════════════

const visits = $input.all();
const today = new Date();

// Find the first pending visit that's in the future
const nextVisit = visits
  .map(v => v.json)
  .filter(v => v.status === 'pending')
  .filter(v => new Date(v.target_date) > today)
  .sort((a, b) => new Date(a.target_date) - new Date(b.target_date))[0];

if (!nextVisit) {
  return [{ json: { skip: true, reason: 'No upcoming visits to schedule' } }];
}

// Determine what diagnostics this visit needs
const diags = nextVisit.diagnostics_needed.split(', ').map(d => d.trim());
const needsScan = diags.some(d => d.startsWith('ultrasound') || d === 'nst');
const needsLab = diags.some(d => !d.startsWith('ultrasound') && d !== 'nst');

// Build the bundled schedule
// Rule: Lab first → Scan second → Consultation last
// Default morning slots, 15 min gaps between steps
const visitDate = nextVisit.target_date;
let labTime = '';
let scanTime = '';
let consultTime = '';

if (needsLab && needsScan) {
  labTime = '09:30';
  scanTime = '09:45';  // Blood draw takes ~10 min
  consultTime = '10:30'; // Anomaly scan takes ~30 min
} else if (needsScan && !needsLab) {
  scanTime = '09:30';
  consultTime = '10:15';
} else if (needsLab && !needsScan) {
  labTime = '09:30';
  consultTime = '10:00';
} else {
  consultTime = '09:30'; // Consultation only
}

return [{
  json: {
    patient_id: nextVisit.patient_id,
    patient_name: nextVisit.patient_name,
    primary_ob: nextVisit.primary_ob,
    visit_number: nextVisit.visit_number,
    visit_type: nextVisit.visit_type,
    gestational_week: nextVisit.gestational_week,
    scheduled_date: visitDate,
    lab_time: labTime,
    scan_time: scanTime,
    consultation_time: consultTime,
    diagnostics_needed: nextVisit.diagnostics_needed,
    needs_scan: needsScan,
    needs_lab: needsLab,
    notes: nextVisit.notes
  }
}];

// Generate WhatsApp confirmation message for the patient
const visit = $input.all()[0].json;

let message = `Hi ${visit.patient_name}! Your visit has been scheduled at Apollo Cradle.\n\n`;
message += `📅 Date: ${visit.scheduled_date}\n\n`;
message += `Your visit schedule:\n`;

if (visit.lab_time) {
  message += `🩸 ${visit.lab_time} — Blood test (Ground Floor Lab)\n`;
}
if (visit.scan_time) {
  message += `📷 ${visit.scan_time} — Ultrasound (2nd Floor)\n`;
}
message += `👩‍⚕️ ${visit.consultation_time} — Dr. ${visit.primary_ob} consultation\n`;
message += `\nEstimated total time: ${visit.needs_scan ? '75-90' : '30-45'} minutes\n`;
message += `\nWe'll send you a quick check-in form the evening before. See you soon!`;

return [{ json: { phone: visit.patient_id, message: message } }];

// Filter for tomorrow's appointments only
const allVisits = $input.all();
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowStr = tomorrow.toISOString().split('T')[0];

const tomorrowVisits = allVisits
  .filter(v => v.json.scheduled_date === tomorrowStr)
  .filter(v => v.json.status === 'scheduled');

if (tomorrowVisits.length === 0) {
  return [{ json: { skip: true, reason: 'No appointments tomorrow' } }];
}

return tomorrowVisits;

// Compose the pre-visit intake message for each patient
const visit = $input.all()[0].json;

const message = `Hi ${visit.patient_name}! 👋

Your visit is tomorrow at Apollo Cradle.

📅 ${visit.scheduled_date}
${visit.lab_time ? '🩸 ' + visit.lab_time + ' — Blood test\n' : ''}${visit.scan_time ? '📷 ' + visit.scan_time + ' — Ultrasound\n' : ''}👩‍⚕️ ${visit.consultation_time} — Dr. ${visit.primary_ob}

Quick check before your visit (reply with numbers):

1️⃣ Any new symptoms since your last visit? (describe briefly, or type "none")

2️⃣ Are you taking your prescribed supplements regularly? (yes/no)

3️⃣ Any specific concerns you want Dr. ${visit.primary_ob} to address tomorrow?

Please reply to this message — it helps your doctor prepare for your visit. 🙏`;

return [{
  json: {
    patient_id: visit.patient_id,
    patient_name: visit.patient_name,
    primary_ob: visit.primary_ob,
    phone: visit.patient_id,
    visit_date: visit.scheduled_date,
    gestational_week: visit.gestational_week,
    visit_type: visit.visit_type,
    message: message
  }
}];

// Extract patient ID and response text from WhatsApp webhook
const body = $input.all()[0].json.body;

// WhatsApp webhook payload structure
const entry = body.entry?.[0];
const changes = entry?.changes?.[0];
const message = changes?.value?.messages?.[0];

if (!message) {
  return [{ json: { skip: true, reason: 'No message in webhook' } }];
}

return [{
  json: {
    patient_phone: message.from,
    response_text: message.text?.body || '',
    timestamp: message.timestamp,
    message_id: message.id
  }
}];

// ═══════════════════════════════════════════════════════
// AUTO-SCHEDULE NEXT BUNDLED VISIT
// Reads the care plan, finds the next pending milestone,
// and schedules it as a coordinated bundle
// NO AI — deterministic scheduling
// ═══════════════════════════════════════════════════════

const input = $input.all()[0].json;
const patientId = input.body.patient_id;

// Mark current visit as completed in care plan
const currentVisit = {
  patient_id: patientId,
  visit_number: input.body.visit_number,
  status: 'completed',
  actual_date: new Date().toISOString().split('T')[0]
};

return [{ json: {
  patient_id: patientId,
  patient_name: input.body.patient_name,
  primary_ob: input.body.doctor_name,
  current_visit_completed: currentVisit,
  schedule_next: true,
  message: 'Current visit marked complete. Next bundled visit will be scheduled by Workflow 01.'
} }];

// Filter for results that are now ready
const pending = $input.all();
const ready = pending.filter(r => r.json.status === 'ready' && !r.json.sent_to_patient);

if (ready.length === 0) {
  return [{ json: { skip: true } }];
}

return ready.map(r => {
  // Simple classification: are all values normal?
  const allNormal = r.json.abnormal_flags === 'none';

  let message;
  if (allNormal) {
    message = `Hi ${r.json.patient_name}! Your blood test results from today's visit are in — everything looks normal. ✅\n\nDetailed results are available at your next visit with Dr. ${r.json.doctor_name}. No action needed from your side.`;
  } else {
    message = `Hi ${r.json.patient_name}, your blood test results from today's visit are ready. Dr. ${r.json.doctor_name} will review them and reach out if any follow-up is needed.\n\nNothing to worry about — some values just need a closer look. You'll get a full review at your next visit.`;
  }

  return { json: { ...r.json, message, allNormal } };
});

// ═══════════════════════════════════════════════════════
// MISSED MILESTONE DETECTOR
// Identifies patients approaching time-critical milestones
// with no appointment booked
//
// Time-critical milestones:
// - NT scan: must be 11w0d to 13w6d
// - Anomaly scan: must be 18w to 22w
// - Glucose challenge: must be 24w to 28w
// - GBS swab: must be 35w to 37w
//
// NO AI — this is date arithmetic
// ═══════════════════════════════════════════════════════

const allVisits = $input.all().map(v => v.json);

// Define time-critical windows (gestational weeks)
const criticalWindows = {
  'nt_scan': { earliest: 11, latest: 13, label: 'NT Scan', urgency: 'high' },
  'anomaly_scan': { earliest: 18, latest: 22, label: 'Anomaly Scan', urgency: 'high' },
  'glucose_test': { earliest: 24, latest: 28, label: 'Glucose Challenge Test', urgency: 'medium' },
};

const today = new Date();
const alerts = [];

// Group visits by patient
const byPatient = {};
for (const v of allVisits) {
  if (!byPatient[v.patient_id]) byPatient[v.patient_id] = [];
  byPatient[v.patient_id].push(v);
}

for (const [patientId, visits] of Object.entries(byPatient)) {
  for (const visit of visits) {
    // Only check pending/unscheduled critical milestones
    if (visit.status !== 'pending') continue;

    const window = criticalWindows[visit.visit_type];
    if (!window) continue; // Not a time-critical visit

    const targetDate = new Date(visit.target_date);
    const daysUntilTarget = Math.floor((targetDate - today) / (1000 * 60 * 60 * 24));

    // Calculate the latest possible date (end of gestational window)
    // Approximate: each week ≈ 7 days from target
    const windowRemaining = (window.latest - visit.gestational_week) * 7 + daysUntilTarget;

    // Alert if:
    // - Less than 14 days until the window closes AND not scheduled
    // - OR the window has already passed (missed)
    if (windowRemaining < 14 && !visit.scheduled_date) {
      const status = windowRemaining < 0 ? 'MISSED' : 'CLOSING SOON';
      alerts.push({
        json: {
          patient_id: patientId,
          patient_name: visit.patient_name,
          primary_ob: visit.primary_ob,
          milestone: window.label,
          gestational_week: visit.gestational_week,
          window_closes_in_days: Math.max(0, windowRemaining),
          status: status,
          urgency: window.urgency,
          action_needed: status === 'MISSED'
            ? `${window.label} window has closed. Consult ${visit.primary_ob} for alternative plan.`
            : `Priority-book ${window.label} within ${windowRemaining} days. Patient at ${visit.gestational_week} weeks.`,
          target_date: visit.target_date
        }
      });
    }
  }
}

if (alerts.length === 0) {
  return [{ json: { skip: true, message: 'No milestone alerts this week.' } }];
}

// Sort by urgency: MISSED first, then by days remaining
alerts.sort((a, b) => {
  if (a.json.status === 'MISSED' && b.json.status !== 'MISSED') return -1;
  if (b.json.status === 'MISSED' && a.json.status !== 'MISSED') return 1;
  return a.json.window_closes_in_days - b.json.window_closes_in_days;
});

return alerts;

// Compile all alerts into a single coordinator summary
const alerts = $input.all().map(a => a.json);

let summary = `📋 WEEKLY MILESTONE REPORT — ${new Date().toISOString().split('T')[0]}\n`;
summary += `${alerts.length} patient(s) need attention:\n\n`;

for (const alert of alerts) {
  const icon = alert.status === 'MISSED' ? '🔴' : '🟡';
  summary += `${icon} ${alert.patient_name} — ${alert.milestone}\n`;
  summary += `   Status: ${alert.status}`;
  if (alert.window_closes_in_days > 0) {
    summary += ` (${alert.window_closes_in_days} days remaining)`;
  }
  summary += `\n   Action: ${alert.action_needed}\n\n`;
}

summary += `Please priority-book these patients this week.`;

return [{ json: { summary, alert_count: alerts.length } }];
